import { describe, it, expect } from "vitest";
import {
  parseCsvLine,
  patternToRe,
  resolvePath,
  parseMarkdownSections,
} from "../fileUtils.js";

describe("parseCsvLine", () => {
  it("splits simple comma-separated values", () => {
    expect(parseCsvLine("a,b,c")).toEqual(["a", "b", "c"]);
  });

  it("handles quoted values with commas", () => {
    expect(parseCsvLine('"a,b",c')).toEqual(["a,b", "c"]);
  });

  it("handles empty fields", () => {
    expect(parseCsvLine("a,,c")).toEqual(["a", "", "c"]);
  });

  it("trims whitespace", () => {
    expect(parseCsvLine("  a  ,  b  ")).toEqual(["a", "b"]);
  });

  // Added escaped double-quote test for parseCsvLine.
  it("handles escaped double-quotes inside quoted fields", () => {
    expect(parseCsvLine('"say ""hello""",b')).toEqual(['say "hello"', "b"]);
  });
});

describe("patternToRe", () => {
  it("converts glob to regex", () => {
    expect(patternToRe("*.md").test("readme.md")).toBe(true);
    expect(patternToRe("*.md").test("file.txt")).toBe(false);
  });

  it("matches exact name", () => {
    expect(patternToRe("prd.md").test("prd.md")).toBe(true);
    expect(patternToRe("prd.md").test("xprd.md")).toBe(false);
  });

  // Added regex-special char literal matching tests for patternToRe.
  it("matches regex-special chars literally", () => {
    expect(patternToRe("file.txt").test("filextxt")).toBe(false);
    expect(patternToRe("a+b.md").test("a+b.md")).toBe(true);
    expect(patternToRe("a+b.md").test("aaab.md")).toBe(false);
    expect(patternToRe("[draft].md").test("[draft].md")).toBe(true);
    expect(patternToRe("[draft].md").test("d.md")).toBe(false);
  });
});

describe("resolvePath", () => {
  it("replaces {project-root} with root", () => {
    expect(resolvePath("{project-root}/_bmad-output", "/home/proj")).toBe(
      "/home/proj/_bmad-output",
    );
  });

  it("returns null for empty or non-string", () => {
    expect(resolvePath("", "/x")).toBe(null);
    expect(resolvePath(null, "/x")).toBe(null);
  });
});

describe("parseMarkdownSections", () => {
  it("extracts ## sections with body", () => {
    const body =
      "## Executive Summary\n\nSome text here.\n\n## Next Section\n\nMore text.";
    const sections = parseMarkdownSections(body, 500);
    expect(sections).toHaveLength(2);
    expect(sections[0].title).toBe("Executive Summary");
    expect(sections[0].body).toContain("Some text here");
    expect(sections[1].title).toBe("Next Section");
    expect(sections[1].body).toContain("More text");
  });

  it("truncates long section body with maxSectionLength", () => {
    const body = "## One\n\n" + "x".repeat(500);
    const sections = parseMarkdownSections(body, 50);
    expect(sections[0].body.length).toBeLessThanOrEqual(51);
    expect(sections[0].body.endsWith("…")).toBe(true);
  });

  it("returns empty array for empty or null body", () => {
    expect(parseMarkdownSections("")).toEqual([]);
    expect(parseMarkdownSections(null)).toEqual([]);
  });
});
